-- packed
local K=90
local _b=""
local bs="ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/"
local function dec(data)
	data=string.gsub(data,"[^"..bs.."=]","")
	return (data:gsub(".",function(x)
		if x=="=" then return "" end
		local r,f="",(string.find(bs,x)-1)
		for i=6,1,-1 do r=r..((f%2^i-f%2^(i-1)>0) and "1" or "0") end
		return r
	end):gsub("%d%d%d?%d?%d?%d?%d?%d?",function(x)
		if #x~=8 then return "" end
		local c=0
		for i=1,8 do c=c+(x:sub(i,i)=="1" and 2^(8-i) or 0) end
		return string.char(c)
	end))
end
local raw=dec(_b)
local o={}
for i=1,#raw do o[i]=string.char(bit32.bxor(string.byte(raw,i),K)) end
local fn=loadstring(table.concat(o))
if fn then fn() else warn("[GQ] load failed") end